export type Step = { op: "quote"; items: unknown[] } | { op: "claim"; policy: number; incident: unknown };
export type Scenario = { customer: Customer; steps: Step[] };
export type Result = { premium: number } | { payout: number; remainingCap: number };

export const runScenario = (_scenario: Scenario): { results: Result[] } => {
  return undefined as unknown as { results: Result[] };
};

