import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office - Premium (quote)", () => {
  // Base premiums for a single item type
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("a plain sword yields 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it.todo("a plain amulet yields 65 G (60 base + 5 fee)");
  it.todo("a plain staff yields 85 G (80 base + 5 fee)");
  it.todo("a plain potion yields 45 G (40 base + 5 fee)");
  it.todo("a single rune component yields 30 G (25 base + 5 fee)");

  // Multiple items / blocks
  it.todo("two plain swords yield 205 G (2x100 + 5 fee)");
  it.todo("two runes yield 55 G (2x25 + 5 fee, no block)");
  it.todo("three runes form a block yielding 65 G (60 block + 5 fee)");
  it.todo("four runes yield 105 G (4x25 + 5 fee, block requires exactly 3)");
  it.todo("seven runes yield 180 G (7x25 + 5 fee, no block since not exactly 3)");
  it.todo("2 runes + 1 moonstone yield 80 G (75 base + 5 fee, no block - different types)");
  it.todo("3 runes + 3 moonstones yield 125 G (120 base + 5 fee, two separate blocks)");

  // Item-specific modifiers
  it.todo("a cursed sword yields 155 G (100 base + 50 curse + 5 fee)");
  it.todo("a sword with enchantment 5 yields 135 G (100 + 30 high enchantment + 5 fee)");
  it.todo("a sword with enchantment 4 has no high-enchantment surcharge: 105 G");
  it.todo("a cursed sword with enchantment 5 stacks both surcharges: 185 G (100 + 50 + 30 + 5)");

  // Policy-wide modifiers (loyalty, first insurance, follow-up)
  it.todo("long-standing customer (>=2 years) gets 20% loyalty discount: sword yields 85 G (100 - 20 + 5)");
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("first insurance adds 10% surcharge: newcomer sword yields 115 G (100 + 10 + 5)");
  it.todo("second contract gets 15% follow-up discount: 0-year customer second sword yields 105 G (100 + 10 first - 15 followup + 5)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet: item-specific curse applies only to sword, totalling 215 G (100 + 60 + 50 + 5)");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor (197.5 G -> 198 G)");

  // Integration examples
  it.todo("newcomer with a cursed sword yields 165 G");
  it.todo("long-standing customer's second contract: cursed sword enchantment 7 yields 160 G");
});

describe("MHPCO Claim Office - Claim", () => {
  // Standard reimbursement
  it.todo("standard sword damage 500 G yields payout 400 G (full minus 100 G deductible)");
  it.todo("damage to a rune (250 G) of 200 G yields payout 100 G");

  // High enchantment clause
  it.todo("sword with enchantment 8 and damage 1000 G yields payout 400 G (50% rule then deductible)");
  it.todo("sword with enchantment 9 (steel) and damage 1000 G yields payout 400 G");

  // Dragon material clause
  it.todo("dragon-material sword with enchantment 5 and damage 800 G yields payout 700 G (full minus deductible)");
  it.todo("dragon-material sword with enchantment 9 and damage 1000 G yields payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword with enchantment 8 and damage 1000 G yields payout 400 G");

  // Deductible per damage event
  it.todo("multi-item damage applies 100 G deductible per damaged item (sword 500 + amulet 300 -> 600 G)");

  // Cap
  it.todo("policy cap is twice the insurance sum (sword: cap 2000 G)");
  it.todo("cursed sword cap is still 2000 G (modifiers do not raise the cap)");
  it.todo("policy with sword + 3 runes has insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("two successive claims of 1500 G against sword: first payout 1400 G then 600 G with remainingCap 0");

  // Multiple items of the same type
  it.todo("two swords on one policy: insurance sum 2000 G, cap 4000 G");
  it.todo("damage entries match policy items by type/count - separate deductibles per entry");

  // Payout rounding
  it.todo("payout rounds down in MHPCO's favor (350.5 G -> 350 G)");
});

describe("MHPCO Claim Office - Error handling", () => {
  it.todo("quote with unknown item type throws an error");
  it.todo("claim referencing an item not in the policy throws an error");
  it.todo("claim with negative damage amount throws an error");
  it.todo("claim with more damage entries of a type than insured throws an error");
});

