export type Customer = { yearsWithMHPCO: number };
export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
export type Step =
  | { op: "quote"; items: Item[] }
  | { op: "claim"; policy: number; incident: unknown };
export type Scenario = { customer: Customer; steps: Step[] };
export type Result = { premium: number } | { payout: number; remainingCap: number };

const PROCESSING_FEE = 5;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);

const itemBasePremium = (item: Item): number => {
  if (item.type in MAIN_ITEM_BASE_PREMIUM) return MAIN_ITEM_BASE_PREMIUM[item.type];
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_BASE_PREMIUM;
  return 0;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  return itemsTotal + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

